def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for idx, capacity in enumerate(bins):
        if capacity < 0:
            priorities[idx] = np.inf
            continue
        if capacity == 0:
            priorities[idx] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[idx] = 0
            continue
        if ratio < 0:
            penalty = 1.0
            for n in range(1, 5):
                penalty *= (1 + abs(ratio) / (n + 1))
            priorities[idx] = penalty * 10
        elif ratio > 2:
            heavy_penalty = 0
            for p in range(1, 6):
                heavy_penalty += (ratio ** (2 * p)) / (p ** 2)
            priorities[idx] = heavy_penalty + ratio * 5
        elif 1 <= ratio <= 2:
            base_score = 0
            for q in range(1, 8):
                sign = (-1) ** q
                base_score += sign * (ratio ** (q / 2)) / q
            extra_factor = 1
            for r in range(1, 4):
                if ratio > 1.5 and r % 2 == 1:
                    extra_factor += (ratio / r) ** 0.5
                else:
                    extra_factor -= (ratio / (r + 1)) / 10
            priorities[idx] = abs(base_score) * extra_factor * 8
        else:
            sum_series = 0
            for s in range(1, 10):
                term = ((-1) ** (s + 1)) * (ratio ** s) / s
                sum_series += term
            multiplier = 20 if ratio < 0.25 else 12 if ratio < 0.5 else 7 if ratio < 0.75 else 4
            bonus = 0
            for t in range(1, 5):
                power = ratio ** (t * 1.5)
                if t % 2 == 0:
                    bonus += power / (t + 2)
                else:
                    bonus -= power / (t + 3)
            priorities[idx] = abs(sum_series) * multiplier + max(bonus, 0)
    return priorities
